import java.util.HashMap;
import java.util.LinkedHashSet;
import java.util.Map;

class LFUCache {
    private int minFreq;
    private int capacity;
    private Map<Integer, Integer> keyValue;
    private Map<Integer, Integer> keyFreq;
    private Map<Integer, LinkedHashSet<Integer>> freqList;

    public LFUCache(int capacity) {
        this.capacity = capacity;
        this.minFreq = 0;
        this.keyValue = new HashMap<>();
        this.keyFreq = new HashMap<>();
        this.freqList = new HashMap<>();
        freqList.put(1, new LinkedHashSet<>());
    }

    public int get(int key) {
        if (!keyValue.containsKey(key)) return -1;
        int count = keyFreq.get(key);
        keyFreq.put(key, count + 1);
        freqList.get(count).remove(key);

        if (count == minFreq && freqList.get(count).size() == 0) minFreq++;

        freqList.computeIfAbsent(count + 1, k -> new LinkedHashSet<>());
        freqList.get(count + 1).add(key);

        return keyValue.get(key);
    }

    public void put(int key, int value) {
        if (capacity <= 0) return;
        if (keyValue.containsKey(key)) {
            keyValue.put(key, value);
            get(key);
            return;
        }
        if (keyValue.size() >= capacity) {
            int evict = freqList.get(minFreq).iterator().next();
            freqList.get(minFreq).remove(evict);
            keyValue.remove(evict);
        }
        keyValue.put(key, value);
        keyFreq.put(key, 1);
        minFreq = 1;
        freqList.get(1).add(key);
    }
}
```


